schemaVersions.applySql:
DROP TABLE IF EXISTS logs; DROP TABLE IF EXISTS users; DROP TABLE IF EXISTS licenses;

CREATE TABLE status (
    name TEXT PRIMARY KEY,
    access_description TEXT
);

CREATE TABLE accounts (
    account_id SERIAL PRIMARY KEY,
    login TEXT UNIQUE NOT NULL,
    password_hash TEXT NOT NULL,
    status_name TEXT REFERENCES status(name)
);

CREATE TABLE employees (
    employee_id VARCHAR PRIMARY KEY,
    last_name TEXT,
    first_name TEXT,
    middle_name TEXT,
    account_id INTEGER REFERENCES accounts(account_id)
);

CREATE TABLE companies (
    company_name TEXT PRIMARY KEY,
    date_added TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    city TEXT,
    contacts JSONB
);

CREATE TABLE modules (
    module_name TEXT PRIMARY KEY,
    description TEXT
);

CREATE TABLE licenses (
    license_key TEXT PRIMARY KEY,
    company_name TEXT REFERENCES companies(company_name),
    issue_date DATE,
    expired_date DATE,
    hwid TEXT
);

CREATE TABLE license_modules (
    license_key TEXT REFERENCES licenses(license_key) ON DELETE CASCADE,
    module_name TEXT REFERENCES modules(module_name) ON DELETE CASCADE,
    PRIMARY KEY(license_key, module_name)
);

CREATE TABLE generations (
    id SERIAL PRIMARY KEY,
    employee_id VARCHAR REFERENCES employees(employee_id),
    generated_key TEXT REFERENCES licenses(license_key) ON DELETE CASCADE,
    generation_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

